    private void loginBTNActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_loginBTNActionPerformed
Sound s = new Sound();
        if(textField_Username.getText().isEmpty() ){
            s.ErrorSound();
            JOptionPane.showMessageDialog(this, "Username should not be empty!");
        }else if(textField_Password.getText().isEmpty() ){
            s.ErrorSound();
            JOptionPane.showMessageDialog(this, "Password should not be empty!");
        } else if(textField_Username.getText().isEmpty()==false || textField_Password.getText().isEmpty()==false) {
             String inputUsername = textField_Username.getText();
            
             String user,pw,rl;
             //String databaseURL = "jdbc:ucanaccess://C:\\Users\\User\\Documents\\NetBeansProjects\\UNION BANK SYSTEM\\src\\database\\Userdb.accdb";
             String databaseURL = "jdbc:ucanaccess://src\\database\\Userdb.accdb";
  
                try (Connection connection = DriverManager.getConnection(databaseURL)) {
                System.out.println("connected");
                String sql = "select * from User Where UserName='" + inputUsername + "'";
                Statement statment=connection.createStatement();
                ResultSet result = statment.executeQuery(sql);
                 if (!result.isBeforeFirst()) {
                    System.out.println("Records not found.");
                        s.ErrorSound();
                        JOptionPane.showMessageDialog(this,"Login error! Please check your username and password carefully!");
                }
                while(result.next()){
                   user=result.getString("UserName");
                   pw = result.getString("password");
                   rl = result.getString("role"); 
                    System.out.println(user+" "+pw);
                    
                   if(password.equals(pw)&&inputUsername.equals(user)){
                        V v=new V();
                        v.setRole(rl);
                        v.setName(user);
                        s.LoginSound();
                        if("Admin".equals(rl)){
                        OptionMenu am = new OptionMenu();
                        am.setVisible(true);
                        this.dispose();                    
                        }else if("User".equals(rl)){
                        UserProfile up = new UserProfile();
                        up.setVisible(true);
                        this.dispose();  
                        }else{
                        s.ErrorSound();
                        JOptionPane.showMessageDialog(this,"Login error! Please contact the authorities!");  
                        }
                    }else if (!password.equals(pw)){
                        System.out.println("Please check your password carefully.");
                    s.ErrorSound();
                        JOptionPane.showMessageDialog(this,"Login error! Please check your password carefully!");
                }
                
                }
                connection.close();  
                }catch (Exception e){
                System.err.println("Got an exception!");
              
                e.printStackTrace();
                
                System.out.println(e); 
                }
        }       
    }//GEN-LAST:event_loginBTNActionPerformed

