    private void textField_PasswordKeyReleased(java.awt.event.KeyEvent evt) {//GEN-FIRST:event_textField_PasswordKeyReleased
      
                char keyChar = evt.getKeyChar();
                int keyCode = evt.getKeyCode();

                // Check if keyChar is a letter or digit
                if (Character.isLetterOrDigit(keyChar)) {
                    password += keyChar;
                } else if (keyCode == KeyEvent.VK_BACK_SPACE) {
                    // Handle backspace
                    if (password.length() > 0) {
                        password = password.substring(0, password.length() - 1);
                    }
                } else if (keyCode == KeyEvent.VK_DELETE) {
                    // Handle delete (assuming deletion happens at the end)
                    if (password.length() > 0) {
                        int caretPosition = textField_Password.getCaretPosition();
                        if (caretPosition < password.length()) {
                            password = password.substring(0, caretPosition) + password.substring(caretPosition + 1);
                        }
                    }
                } else {
                    evt.consume();
                }

                // Mask the password
                StringBuilder maskedPassword = new StringBuilder();
                for (int i = 0; i < password.length(); i++) {
                    maskedPassword.append("*");
                }

                // Update the text field and caret position
                textField_Password.setText(maskedPassword.toString());
                textField_Password.setCaretPosition(maskedPassword.length());

                // Print the current stored password (for debugging purposes)
                System.out.print(password);
           
    }//GEN-LAST:event_textField_PasswordKeyReleased

